// Build a rolling date window from today back N days.
// DAYS_BACK comes from the Config node.

const cfg      = $input.first().json;
const daysBack = cfg.DAYS_BACK || 30;

const pad = n => String(n).padStart(2, '0');

const now  = new Date();
const from = new Date(now);
from.setDate(now.getDate() - daysBack);

const fmt = d => `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`;

return [{
  json: {
    DOMAIN:     cfg.DOMAIN,
    BASE_URL:   cfg.BASE_URL,
    DAYS_BACK:  daysBack,
    DATE_FROM:  fmt(from) + ' 00:00:00',
    DATE_TO:    fmt(now)  + ' 23:59:59',
    LABEL_FROM: fmt(from),
    LABEL_TO:   fmt(now)
  }
}];

// ── Strip device-type suffixes from Netsapiens user IDs ──────
// Netsapiens appends suffixes to extension numbers:
// 775  → physical desk phone (base user)
// 775t → softphone/trunk device
// 775wp → web portal / SNAPmobile Web
// 775i → iOS SNAPmobile app
// 775m → mobile / Android
// 775ai → AI agent / virtual device
// Longest suffixes must be checked first (wp before p, ai before i)

const SUFFIXES = ['wp', 'ai', 't', 'i', 'm'];

function getBaseUser(user) {
  if (!user) return null;
  const s = String(user).trim();
  for (const suffix of SUFFIXES) {
    if (s.toLowerCase().endsWith(suffix)) {
      return s.slice(0, s.length - suffix.length);
    }
  }
  return s;
}

// Add base_user to every CDR record.
// We derive it from call_term_user (the called/internal party).
// call_through_user is used as fallback for forwarded calls.
const enriched = $input.all().map(item => {
  const raw = item.json;
  const userSource = raw.call_term_user || raw.call_through_user || null;
  return {
    json: {
      ...raw,
      base_user:   getBaseUser(userSource),
      device_type: getDeviceType(userSource)
    }
  };
});

function getDeviceType(user) {
  if (!user) return 'unknown';
  const s = String(user).toLowerCase().trim();
  if (s.endsWith('wp'))  return 'Web Portal';
  if (s.endsWith('ai'))  return 'AI Agent';
  if (s.endsWith('t'))   return 'Softphone';
  if (s.endsWith('i'))   return 'iOS App';
  if (s.endsWith('m'))   return 'Mobile App';
  return 'Desk Phone';
}

if (enriched.length === 0) {
  return [{ json: { _empty: true, records: [] } }];
}

// Pass all records as a single JSON array on one item.
// The dashboard builder (next node) needs the full dataset.
return [{
  json: {
    records: enriched.map(i => i.json),
    total:   enriched.length
  }
}];
